def validate(args, outputs):
    ops, arg_lists = args
    if not isinstance(outputs, list) or len(outputs) != len(ops):
        return False
    if ops[0] != 'Solution':
        return False
    n, blacklist = arg_lists[0]
    bl = set(blacklist)
    for i in range(1, len(ops)):
        op, out = ops[i], outputs[i]
        if op == 'pick':
            if not isinstance(out, int) or isinstance(out, bool):
                return False
            if out < 0 or out >= n:
                return False
            if out in bl:
                return False
    return True

