import random


class Solution:
    def __init__(self, n, blacklist):
        bl = set(blacklist)
        self.m = n - len(bl)
        self.remap = {}
        tail = iter(x for x in range(self.m, n) if x not in bl)
        for b in bl:
            if b < self.m:
                self.remap[b] = next(tail)

    def pick(self):
        x = random.randrange(self.m)
        return self.remap.get(x, x)

solutions.javascript:
var Solution = function(n, blacklist) {
    const bl = new Set(blacklist);
    this.m = n - bl.size;
    this.remap = new Map();
    const tail = [];
    for (let x = this.m; x < n; x++) {
        if (!bl.has(x)) tail.push(x);
    }
    let ti = 0;
    for (const b of bl) {
        if (b < this.m) {
            this.remap.set(b, tail[ti++]);
        }
    }
};

Solution.prototype.pick = function() {
    const x = Math.floor(Math.random() * this.m);
    return this.remap.has(x) ? this.remap.get(x) : x;
};
